using System;using System.Collections.Generic;using System.Drawing;using System.Windows.Forms;
namespace PremiumLivingFurnitureWinForms;
public class RecordForm:Form{readonly List<FieldDefinition> fields;readonly Dictionary<string,Control> inputs=new();public Dictionary<string,object?> Values{get;}=new();public RecordForm(string title,List<FieldDefinition> fields){this.fields=fields;Text=title;StartPosition=FormStartPosition.CenterParent;Size=new Size(850,Math.Min(960,220+fields.Count*58));Font=Theme.DefaultFont;BackColor=Theme.AppBg;var root=new TableLayoutPanel{Dock=DockStyle.Fill,ColumnCount=2,Padding=new Padding(26),AutoScroll=true,BackColor=Theme.AppBg};root.ColumnStyles.Add(new ColumnStyle(SizeType.Absolute,240));root.ColumnStyles.Add(new ColumnStyle(SizeType.Percent,100));for(int i=0;i<fields.Count;i++){var f=fields[i];root.RowStyles.Add(new RowStyle(SizeType.Absolute,58));root.Controls.Add(new Label{Text=f.Required?f.Label+" *":f.Label,Dock=DockStyle.Fill,TextAlign=ContentAlignment.MiddleLeft,ForeColor=Theme.Muted,Font=new Font("Segoe UI",9,FontStyle.Bold)},0,i);var input=CreateInput(f);input.Dock=DockStyle.Fill;input.Margin=new Padding(0,8,0,8);inputs[f.Column]=input;root.Controls.Add(input,1,i);}var buttons=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.RightToLeft,BackColor=Theme.AppBg};var save=Theme.PrimaryButton("Save",110);var cancel=Theme.SecondaryButton("Cancel",110);save.Click+=(_,_)=>Save();cancel.Click+=(_,_)=>DialogResult=DialogResult.Cancel;buttons.Controls.Add(save);buttons.Controls.Add(cancel);root.RowStyles.Add(new RowStyle(SizeType.Absolute,58));root.SetColumnSpan(buttons,2);root.Controls.Add(buttons,0,fields.Count);Controls.Add(root);}static Control CreateInput(FieldDefinition f){if(f.Kind==FieldKind.Password)return new TextBox{UseSystemPasswordChar=true,Text=DefaultValue(f),ReadOnly=f.ReadOnly};if(f.Kind==FieldKind.Integer)return new NumericUpDown{Minimum=-999999,Maximum=999999,Value=ToDecimal(f.DefaultValue),Enabled=!f.ReadOnly};if(f.Kind==FieldKind.Decimal)return new NumericUpDown{Minimum=-999999999,Maximum=999999999,DecimalPlaces=2,Value=ToDecimal(f.DefaultValue),Enabled=!f.ReadOnly};if(f.Kind==FieldKind.Date)return new DateTimePicker{Format=DateTimePickerFormat.Short,Value=DateTime.Today,Enabled=!f.ReadOnly};if(f.Kind==FieldKind.Combo){var c=new ComboBox{DropDownStyle=ComboBoxStyle.DropDownList,Enabled=!f.ReadOnly};c.Items.AddRange(f.Options);if(c.Items.Count>0)c.SelectedIndex=0;return c;}if(f.Kind==FieldKind.Lookup){var c=new ComboBox{DropDownStyle=ComboBoxStyle.DropDownList,Enabled=!f.ReadOnly};if(!string.IsNullOrWhiteSpace(f.LookupTable))foreach(var item in Database.GetLookup(f.LookupTable))c.Items.Add(item);if(c.Items.Count>0)c.SelectedIndex=0;return c;}return new TextBox{Text=DefaultValue(f),ReadOnly=f.ReadOnly};}static string DefaultValue(FieldDefinition f)=>f.DefaultValue is AutoCode code?Database.GenerateNextCode(code.TableName,code.ColumnName,code.Prefix,code.Separator,code.Width):Convert.ToString(f.DefaultValue)??"";static decimal ToDecimal(object? v)=>decimal.TryParse(Convert.ToString(v),out var n)?n:0;void Save(){Values.Clear();foreach(var f in fields){var input=inputs[f.Column];object? value=input switch{TextBox t=>t.Text.Trim(),ComboBox c when f.Kind==FieldKind.Lookup=>c.SelectedItem is LookupItem li?li.Id:null,ComboBox c=>c.Text,NumericUpDown n when f.Kind==FieldKind.Integer=>(int)n.Value,NumericUpDown n=>n.Value,DateTimePicker d=>d.Value.ToString("yyyy-MM-dd"),_=>null};if(f.Required&&(value==null||string.IsNullOrWhiteSpace(Convert.ToString(value)))){MessageBox.Show($"Please enter {f.Label} before saving.");return;}Values[f.Column]=value;}DialogResult=DialogResult.OK;}}
